import React from "react"
import _ from "lodash"
import styled from "styled-components"
import { graphql, navigate } from "gatsby"

import Layout from "components/Layout"
import SEO from "components/SEO"
import PostList from "components/PostList"
import SideTagList from "components/SideTagList"
import Info from "components/Info"
import PopularPosts from "components/PopularPosts"

import { title, description, siteUrl } from "../../gatsby-meta-config"

const RelativeWrapper = styled.div`
  position: relative;
`

const RightSidebar = styled.aside`
  position: absolute;
  left: calc(100% + 36px);
  top: 0;
  width: 200px;

  @media (max-width: 1300px) {
    display: none;
  }
`

const SidebarDivider = styled.hr`
  border: none;
  border-bottom: 1px solid ${props => props.theme.colors.divider};
  margin: 24px 0;
`

const BlogIndex = ({ data }) => {
  const posts = data.allMarkdownRemark.nodes
  const tags = _.sortBy(data.allMarkdownRemark.group, ["totalCount"]).reverse()
  const { author, language } = data.site.siteMetadata;

  if (posts.length === 0) {
    return (
      <p>
        No blog posts found. Add markdown posts to &quot;content/blog&quot; (or
        the directory you specified for the &quot;gatsby-source-filesystem&quot;
        plugin in gatsby-config.js).
      </p>
    )
  }

  return (
    <Layout>
      <SEO title={title} description={description} url={siteUrl} />
      <Info author={author} language={language} />
      <RelativeWrapper>
        <RightSidebar>
          <PopularPosts allPosts={posts} />
          <SidebarDivider />
          <SideTagList tags={tags} postCount={posts.length} />
        </RightSidebar>
        <PostList
          postList={posts}
          currentPage={1}
          onPageChange={page => navigate(`/posts?page=${page}`)}
        />
      </RelativeWrapper>
    </Layout>
  )
}

export default BlogIndex

export const pageQuery = graphql`
query BlogIndex {
  site {
    siteMetadata {
      title
      language
      author {
        name
        bio {
          role
          description
          thumbnail
        }
      }
      links {
        github
        linkedIn
        email
      }
    }
  }
    
  allMarkdownRemark(
  sort: {frontmatter: {date: DESC}}
  filter: {frontmatter: {publish: {eq: true}}}
  ) {
    group(field: {frontmatter: {tags: SELECT}}) {
      fieldValue
      totalCount
    }
    nodes {
      excerpt(pruneLength: 150, truncate: true)
      fields {
        slug
      }
      frontmatter {
        date(formatString: "MMMM DD, YYYY")
        updated(formatString: "MMM DD, YYYY")
        title
        description
        tags
      }
    }
  }
}
`